head.script:
	// imports("uiplugin._popup");
	scwin.EV_TABLENAME;
	scwin.EV_RESULTRFC;
	scwin.data9;
	scwin.data8;
	scwin.data7;
	scwin.popupParam;

	scwin.initScreen = function() {
		scwin.popupParam=comLib.getPopupParam($p,["useChkBox", "rfcNm", "ivF4Case"
		,"isFieldNm1", "isFieldNm2" ,"isFieldNm3" ,"isFieldNm4","isFieldNm5", "isFieldNm6"
		,"isFieldVal1","isFieldVal2","isFieldVal3","isFieldVal4","isFieldVal5","isFieldVal6"]);
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, scwin.popupParam.popupID);
		// 화면구성 조회
		scwin.initSearch();
	};

	/**
	* 화면구성 조회
	*/
	scwin.initSearch = function() {
		// Search Help 팝업 화면구성
		// 샘플
		var requestData = {"RFC_NAME" : scwin.popupParam.rfcNm //"ZKCT_F4_INIT_SAMPLE" //ZKCT_F4_INIT_SAMPLE
							, "IS_FIELD1" : { "FIELDNAME" : scwin.popupParam.isFieldNm1, "FIELDVAL" : scwin.popupParam.isFieldVal1 }	//CARRID,AF
							, "IS_FIELD2" : { "FIELDNAME" : scwin.popupParam.isFieldNm2, "FIELDVAL" : scwin.popupParam.isFieldVal2 }	//CARRNAME, Air*
							, "IS_FIELD3" : { "FIELDNAME" : scwin.popupParam.isFieldNm3, "FIELDVAL" : scwin.popupParam.isFieldVal3 }
							, "IS_FIELD4" : { "FIELDNAME" : scwin.popupParam.isFieldNm4, "FIELDVAL" : scwin.popupParam.isFieldVal4 }
							, "IS_FIELD5" : { "FIELDNAME" : scwin.popupParam.isFieldNm5, "FIELDVAL" : scwin.popupParam.isFieldVal5 }
							, "IS_FIELD6" : { "FIELDNAME" : scwin.popupParam.isFieldNm6, "FIELDVAL" : scwin.popupParam.isFieldVal6 }
							, "IV_F4_CASE" : scwin.popupParam.ivF4Case //"SRCH1"	//SRCH1
							, "EXPORT_TABLE" : ["TT_COMBO1", "TT_COMBO2", "TT_COMBO3", "TT_COMBO4", "TT_COMBO5", "TT_COMBO6", "TT_MAPPING", "TT_OPTION", "TT_RESULT"]
							, "EXPORT_RESULT" : ["EV_TABLENAME", "EV_RESULTRFC", "EV_VALCOUNT"]
						};

			// 샘플
//			var requestData = {  "RFC_NAME" : "ZKCT_F4_INIT_SAMPLE" //ZKCT_F4_INIT_SAMPLE
//								, "IS_FIELD1" : { "FIELDNAME" : "", "FIELDVAL" : "" }	//CARRID,AA
//								, "IV_F4_CASE" : "SRCH1"	//SRCH1
//								, "EXPORT_TABLE" : [ "TT_COMBO1", "TT_COMBO2", "TT_COMBO3", "TT_COMBO4", "TT_COMBO5", "TT_COMBO6", "TT_MAPPING", "TT_OPTION", "TT_RESULT" ]
//								, "EXPORT_RESULT" : [ "EV_TABLENAME", "EV_RESULTRFC", "EV_VALCOUNT" ]
//							};

			// 건설
//			var requestData = {  "RFC_NAME" : "ZPSZ_F4_SCODE_LIST_INIT" //ZPSZ_F4_SCODE_LIST_INIT
//								, "IS_FIELD1" : { "FIELDNAME" : "", "FIELDVAL" : "" }	//
//								, "IV_F4_CASE" : "SRCH1"
//								, "EXPORT_TABLE" : [ "TT_COMBO1", "TT_COMBO2", "TT_COMBO3", "TT_COMBO4", "TT_COMBO5", "TT_COMBO6", "TT_MAPPING", "TT_OPTION", "TT_RESULT" ]
//								, "EXPORT_RESULT" : [ "EV_TABLENAME", "EV_RESULTRFC", "EV_VALCOUNT" ]
//							};

			// 예산
//			var requestData = {  "RFC_NAME" : "ZFMZ_F4_INIT_POSID" //ZKCT_F4_INIT_SAMPLE
//								, "IS_FIELD1" : { "FIELDNAME" : "", "FIELDVAL" : "" }	//
//								, "IV_F4_CASE" : "SRCH1"	//SRCH1
//								, "EXPORT_TABLE" : [ "TT_COMBO1", "TT_COMBO2", "TT_COMBO3", "TT_COMBO4", "TT_COMBO5", "TT_COMBO6", "TT_MAPPING", "TT_OPTION", "TT_RESULT" ]
//								, "EXPORT_RESULT" : [ "EV_TABLENAME", "EV_RESULTRFC", "EV_VALCOUNT" ]
//							};

			// 예산
//			var requestData = {  "RFC_NAME" : "ZCOZ_F4_INIT_PRCTR"
//								, "IS_FIELD1" : { "FIELDNAME" : "", "FIELDVAL" : "" }	//
//								, "IV_F4_CASE" : "SRCH1"
//								, "EXPORT_TABLE" : [ "TT_COMBO1", "TT_COMBO2", "TT_COMBO3", "TT_COMBO4", "TT_COMBO5", "TT_COMBO6", "TT_MAPPING", "TT_OPTION", "TT_RESULT" ]
//								, "EXPORT_RESULT" : [ "EV_TABLENAME", "EV_RESULTRFC", "EV_VALCOUNT" ]
//							};

				var option = {action : "sc/sap/getCmmnPopup.do", reqData : requestData, resData : "", success : "scwin.initSearchCallback", isShowMeg : false};
				ajaxLib.executeAjax($p, option);
