	/**
	* 화면구성 콜백
	*/
	scwin.initSearchCallback = function(resBody, e) {
		// console.log("initSearchCallback resBody="+JSON.stringify(resBody));
		scwin.data9 = resBody.data.data9;
		scwin.data8 = resBody.data.data8;
		scwin.data7 = resBody.data.data7;
		/*
		data9 = resBody.data.data9;
		data8 = resBody.data.data8;
		data7 = resBody.data.data7;
		data6 = resBody.data.data6;
		data5 = resBody.data.data5;
		data4 = resBody.data.data4;
		data3 = resBody.data.data3;
		data2 = resBody.data.data2;
		data1 = resBody.data.data1;
		*/
		scwin.EV_TABLENAME = resBody.data.EV_TABLENAME;
		scwin.EV_RESULTRFC = resBody.data.EV_RESULTRFC;

		// 조회조건 구성
		scwin.makeCondition(resBody.data.data8);
		// scwin.makeCondition();

		// SelectBox 구성
		scwin.makeSelectBox(resBody);

		// GridView 동적 생성
		scwin.setColumnID();
	};

		/**
		* 조회
		*/
		scwin.btnQuery_onclick = function() {
			// TT_OPTION : 조회조건 설정
			for (var i=0; i<data8.length; i++) {
				if (data8[i].CB_FLG == "X") {
					data8[i].LOW = $p.getComponentById(("acbData"+i).getValue());
				} else {
					data8[i].LOW = $p.getComponentById(("iptData"+i).getValue());
				}
			}

			// Search Help 팝업 조회
			var requestData = {"RFC_NAME" : scwin.EV_RESULTRFC
								, "IV_TABLENAME" : scwin.EV_TABLENAME
								, "IV_MAXREC" : iptData6.getValue()
								, "IMPORT_TABLE" : [ { "TT_OPTION" : scwin.data8 } //[{"CB_NM":"TT_COMBO1","CB_FLG":"X","FIELDDESC":"항공사","LOW":"","FIELDNAME":"CARRID","OPTION":"EQ"},{"CB_NM":"","CB_FLG":"","FIELDDESC":"항공사명","LOW":"","FIELDNAME":"CARRNAME","OPTION":"EQ"}] }
								, {"TT_MAPPING" : scwin.data7 } //[{"MAPNAME":"VAL1","FIELDDESC":"항공사","FIELDNAME":"CARRID","DISP_FLG":"X","RET_FLG":"X","FWIDTH":"3"},{"MAPNAME":"VAL2","FIELDDESC":"항공사명","FIELDNAME":"CARRNAME","DISP_FLG":"X","RET_FLG":"","FWIDTH":"15"}] }
							]
								, "EXPORT_TABLE" : ["TT_RESULT"]
							};

			var option = {action : "sc/sap/getCmmnPopup.do", reqData : requestData, resData : "", success : "scwin.btnQueryCallback", isShowMeg : false};
			ajaxLib.executeAjax($p, option);
		};

		/**
		 * 조회 콜백
		 */
		scwin.btnQueryCallback = function(resBody, e) {
//			console.log("btnQueryCallback resBody="+JSON.stringify(resBody));
			dltList.setJSON(resBody.data.data1);
			txtQryRsltCnt.setValue(dltList.getRowCount());
		};

		/**
		 * 확인
		 */
		scwin.btnConfirm_onclick = function(e) {
			var rowIdx = grdView.getFocusedRowIndex();
			var colIdx = grdView.getFocusedColumnIndex();

			if (rowIdx < 0) return;
			if (utilLib.isNull(pparam)) {
				window.close();
			}

			var arrData = utilLib.getCheckedData(dltList);
			comLib.closePopupCall($p,scwin.popupParam,true, arrData != [] ? arrData : dltList.getRowJSON(rowIdx));
		};

		/**
		 * GridView Cell 더블 클릭
		 */
		scwin.grdView_oncelldblclick = function(row, col) {
			var rowIdx = grdView.getFocusedRowIndex();
			var colIdx = grdView.getFocusedColumnIndex();
			var rtnData = dltList.getCellData(rowIdx, colIdx);
			comLib.closePopupCall($p, scwin.popupParam, true, dltList.getRowJSON(rowIdx));
		};

		/**
		 * 조회조건 구성
		 */
		scwin.makeCondition = function(data8) {
			// TT_OPTION 개수에 따른 조회조건 구성(show/hide)
			grpCond2.hide();
			grpCond3.hide();

			if (data8.length > 2 && data8.length <=4) {
				grpCond2.show();
			}
			if (data8.length > 4) {
				grpCond2.show();
				grpCond3.show();
			}

			for(var i=0; i<6; i++) {
				$p.getComponentById("txtTitle" + i).hide();
				$p.getComponentById("acbData" + i).hide();
				$p.getComponentById("iptData" + i).hide();
			}

			// TT_OPTION	
//			var data8 = [{"CB_FLG":"X","FIELDDESC":"항공사","LOW":"","FIELDNAME":"CARRID","OPTION":"EQ"}
//							,{"CB_FLG":"","FIELDDESC":"항공사명","LOW":"","FIELDNAME":"CARRNAME","OPTION":"CP"}];

			for (var i = 0; i < data8.length; i++) {
				// title 구성
				$p.getComponentById("txtTitle"+i).setValue(data8[i].FIELDDESC);

				// selectBox, inputBox 사용여부
				if (data8[i].CB_FLG == "X") { // selectBox
					$p.getComponentById("txtTitle"+i).show();
					$p.getComponentById("acbData"+i).show();
				} else { //inputBox
					$p.getComponentById("txtTitle"+i).show();
					$p.getComponentById("iptData"+i).show();
					$p.getComponentById("iptData"+i).setValue(data8[i].LOW);
				}

				// 최대적중수
				iptData6.setValue(500);
			}
		};

		/**
		 * SelectBox 개수 리턴
		 * @return cnt selectBox 개수 리턴
		 */
		scwin.getCboCnt = function() {
			var cnt = 0;

			if (data1.length > 0) cnt++;
			if (data2.length > 0) cnt++;
			if (data3.length > 0) cnt++;
			if (data4.length > 0) cnt++;
			if (data5.length > 0) cnt++;
			if (data6.length > 0) cnt++;

			return cnt;
		};

		/**
		 * OPTION display
		 * @param value
		 */
		scwin.displayOption = function(value) {
			var sign = false;
			/*
			EQ : 같다 '='
			NE : 같지 않다 '<>'
			GE : 이상 '>='
			GT : 초과 '>'
			LE : 이하 '<='
			LT : 미만 '<'
			CP : 문자열 포함 찾기 '[*]'
			*/
			if (sign) { //기호
				switch (value) {
					case "EQ" : return "="; break;
					case "NE" : return "<>"; break;
					case "GE" : return ">="; break;
					case "GT" : return ">"; break;
					case "LE" : return "<="; break;
					case "LT" : return "<"; break;
					case "CP" : return "[*]"; break;
				}
			} else { //한글
				switch (value) {
					case "EQ" : return "같다"; break;
					case "NE" : return "같지 않다"; break;
					case "GE" : return "이상"; break;
					case "GT" : return "초과"; break;
					case "LE" : return "이하"; break;
					case "LT" : return "미만"; break;
					case "CP" : return "문자열 포함"; break;
				}
			}
		};

		/**
		 * selectBox 구성
		 */
		scwin.makeSelectBox = function(resBody) {
			for (var k = 0; k < resBody.data.data8.length; k++) {
				if (data8[k].CB_FLG == "X") {
					for(var i = 0; i < resBody.data["data"+(k+1)].length; i++) {
						resBody.data["data"+(k+1)][i].CB_DES = resBody.data["data"+(k+1)][i].CB_VAL + " - " + resBody.data["data"+(k+1)][i].CB_DES;
					}
					var option = {"id" :"dltData" + k,
					"type" : "dataList",
					"option":{"baseNode": "list", "repeatNode": "map"},
					"columnInfo":[{"id":"CB_DES", "name":"CB_DES", "dataType":"text"},
						{"id":"CB_VAL", "name":"CB_VAL", "dataType":"text"}]
					};
					comLib.createData($p, option);

					$p.getComponentById("dltData" + k).setJSON(resBody.data["data"+(k+1)]);
					$p.getComponentById("acbData" + k).setNodeSet("data:dltData" + k, "CB_DES", "CB_VAL");
					$p.getComponentById("acbData" + k).setValue(resBody.data.data8[k].LOW);
				}
			}
		};

		/**
		 * 동적으로 dataList 생성
		 * @param <String> dataList ID
		 * @param <Array>  columnInfo
		 */
		scwin.makeDataList = function(dltID, columnInfo) {
			comLib.createData($p,{
				"id": dltID,
				"type": "dataList",
				"option": {
					"useData": false
				},
				"columnInfo": columnInfo
			});
		};

	/**
	 * dataList에 넣을 json
	 */
	scwin.setColumnID = function() {
		var column = {};
		var columnArr = [];
		var gridHeader = "", gridBody = "";

		// json의 첫번째 데이터에서 컬럼의 id와 개수 정보 확
		// TT_MAPPING
		// var data7 = [{"MAPNAME":"VAL1","FIELDDESC":"항공사","FIELDNAME":"CARRID","DISP_FLG":"X","RET_FLG":"X","FWIDTH":"3"},{"MAPNAME":"VAL2","FIELDDESC":"항공사명","FIELDNAME":"CARRNAME","DISP_FLG":"X","RET_FLG":"","FWIDTH":"15"}];
		// TT_RESULT
		// var data9 = [{"VAL9":"","VAL1":"AA","VAL2":"American Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"AC","VAL2":"Air Canada","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"AF","VAL2":"Air France","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"AZ","VAL2":"Alitalia","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"BA","VAL2":"British Airways","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"FJ","VAL2":"Air Pacific","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"CO","VAL2":"Continental Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"DL","VAL2":"Delta Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"AB","VAL2":"Air Berlin","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"LH","VAL2":"Lufthansa","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"NG","VAL2":"Lauda Air","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"JL","VAL2":"Japan Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"NW","VAL2":"Northwest Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"QF","VAL2":"Qantas Airways","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"SA","VAL2":"South African Air.","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"SQ","VAL2":"Singapore Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"SR","VAL2":"Swiss","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""},{"VAL9":"","VAL1":"UA","VAL2":"United Airlines","VAL3":"","VAL10":"","VAL4":"","VAL5":"","VAL6":"","VAL7":"","VAL8":""}];

		if (useChkBox) {
			gridHeader = '<w2:column width="15" inputType="checkbox" style="height:40px;" id="chk" value="" displayMode="" checkboxLabel="&amp;nbsp" readOnly="false"></w2:column>';
			gridBody = '<w2:column inputType="checkbox" style="height:34px;" id="chk" displayMode="label" checkboxLabel="&amp;nbsp" readOnly="false"></w2:column>';
			column["id"] = "chk";
			column["dataType"] = "text";
			columnArr.push(column);
		}

		for(var k = 0;k < scwin.data7.length; k++){
		// dataList를 동적으로 만들기 위한 컬럼 정보
		column = {};
		column["id"] = scwin.data7[k].MAPNAME;
		column["dataType"] = "text";
		columnArr.push(column);

		// gridView의 컬럼 정보 정의
		var width = "70";
		// if (data7[k].DISP_FLG == "") width = "0";
		gridHeader +='<w2:column id="'+'h'+k+'" style="height:20px" inputType="text" width="' + width + '" value="'+scwin.data7[k].FIELDDESC+'"></w2:column>';
			if (k==0) {	//code center
				gridBody += '<w2:column id="'+scwin.data7[k].MAPNAME+'" style="height:20px" inputType="text" width="70" textAlign="center"></w2:column>'
			} else { //desc left
				gridBody += '<w2:column id="'+scwin.data7[k].MAPNAME+'" style="height:20px" inputType="text" width="70" textAlign="left"></w2:column>'
			}
		}
		scwin.makeDataList("dltList", columnArr);

		// gridView 정보 정의 
		// xml 형식을 정의 하면 <w2:gridView 에 xmlns:w2="http://www.inswave.com/websquare" xmlns:ev="http://www.w3.org/2001/xml-events" 포함 합니다.
		// 조회조건 1줄이면 gridView height : 375px, 2줄이면 ?px, 3줄이면 300px, 4줄이면 259px
		var gridheight=grdView.getSize( "height" );
		var gridStr = '<w2:gridView xmlns:w2="http://www.inswave.com/websquare" xmlns:ev="http://www.w3.org/2001/xml-events" dataList="dltList" scrollByColumn="false" id="grdView" style="height: '+gridheight+'px;" fixedColumnWithHidden="true" useShiftKey="false" autoFit="" ev:oncelldblclick="scwin.grdView_oncelldblclick" readOnly="true" focusMode="row">'
		+ '<w2:header id="header1">'
		+ '<w2:row id="row1">'
		+ gridHeader
		+ '</w2:row>'
		+'</w2:header>'
		+'<w2:gBody id="gBody1">'
		+'<w2:row id="row2">'
		+ gridBody
		+'</w2:row>'
		+'</w2:gBody>'
		+'</w2:gridView>' ;

		grdView.setGridStyle(WebSquare.xml.parse(gridStr, true));
		dltList.setJSON(scwin.data9);

		txtQryRsltCnt.setValue(dltList.getRowCount());
	};
